// Example: Ultrasonic Distance Sensor
// Measure distance with HC-SR04 on pins 7 (trig) and 8 (echo).

int trigPin = 7;
int echoPin = 8;

void setup() {
  Serial.begin(9600);
  pinMode(trigPin, OUTPUT);
  pinMode(echoPin, INPUT);
}

void loop() {
  digitalWrite(trigPin, LOW);
  delayMicroseconds(2);
  digitalWrite(trigPin, HIGH);
  delayMicroseconds(10);
  digitalWrite(trigPin, LOW);
  long duration = pulseIn(echoPin, HIGH);
  float cm = duration * 0.034 / 2.0;
  Serial.print("Distance: ");
  Serial.print(cm);
  Serial.println(" cm");
  delay(500);
}
